const AF='brightness(0) saturate(100%) invert(75%) sepia(50%) saturate(500%) hue-rotate(185deg) brightness(115%)';

function SportIcon({id,live,sz=36}:{id:string;live:boolean;sz?:number}){
  if(live) return <img src={`/icon-${id}.svg`} alt={id} style={{width:sz,height:sz,objectFit:'contain',filter:AF}}/>;
  const ic=ICON_SVGS[id];
  if(!ic) return <img src={`/icon-${id}.svg`} alt={id} style={{width:sz,height:sz,objectFit:'contain',opacity:.3}}/>;
  return <svg viewBox={ic.vb} style={{width:sz,height:sz,opacity:.35}} dangerouslySetInnerHTML={{__html:ic.svg}}/>;
}

